// Normalize input, generate documentId for RAG scope
const raw = $input.first().json;
const body = raw.body ?? raw;
const text = (body.text ?? body.documentText ?? '').trim();
const query = (body.query ?? '').trim();

if (!text || !query) {
  throw new Error('Request body must include "text" and "query"');
}

// Per-request documentId for Chroma metadata (isolate this document's chunks)
const documentId = body.documentId || `doc-${Date.now()}-${Math.random().toString(36).slice(2, 11)}`;

return [{ json: { text, query, documentId } }];

// Chunk text: ~1000 chars, 200 overlap (Recursive Character style)
const CHUNK_SIZE = 1000;
const CHUNK_OVERLAP = 200;
const input = $input.first().json;
const text = input.text;
const documentId = input.documentId;

const chunks = [];
let start = 0;
while (start < text.length) {
  const end = Math.min(start + CHUNK_SIZE, text.length);
  let chunk = text.slice(start, end);
  if (end < text.length && CHUNK_OVERLAP > 0) {
    const lastSpace = chunk.lastIndexOf(' ', chunk.length - CHUNK_OVERLAP);
    if (lastSpace > 0) chunk = chunk.slice(0, lastSpace + 1);
  }
  if (chunk.trim()) chunks.push({ pageContent: chunk.trim(), documentId });
  start = start + chunk.length - (end < text.length ? CHUNK_OVERLAP : 0);
}

if (chunks.length === 0) chunks.push({ pageContent: text.slice(0, 2000) || '(empty)', documentId });

return chunks.map((c, i) => ({ json: { ...c, chunkIndex: i } }));

// Build Chroma add payload from all chunk+embed items (Merge output)
const items = $input.all();
const extractBody = $('Extract Body').first().json;
const documentId = extractBody.documentId;

const ids = [];
const embeddings = [];
const metadatas = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i].json;
  const embedding = item.embedding ?? (item.embeddings && item.embeddings[0]);
  const docId = item.documentId ?? documentId;
  if (Array.isArray(embedding)) {
    ids.push(`${docId}-${i}`);
    embeddings.push(embedding);
    metadatas.push({ documentId: docId });
  }
}

if (ids.length === 0) throw new Error('No embeddings received from Ollama');

return [{ json: { ids, embeddings, metadatas, documentId } }];

// Pass query and documentId for retrieval
const extractBody = $('Extract Body').first().json;
return [{ json: { query: extractBody.query, documentId: extractBody.documentId } }];

// Build Chroma query payload from merged item (query, documentId, embedding)
const m = $input.first().json;
const query = m.query;
const documentId = m.documentId;
const queryEmbedding = m.embedding ?? (m.embeddings && m.embeddings[0]);

if (!Array.isArray(queryEmbedding)) throw new Error('Query embedding missing');

const chromaQueryBody = {
  query_embeddings: [queryEmbedding],
  n_results: 5,
  where: { documentId }
};

return [{ json: { chromaQueryBody, query } }];

// Build Groq prompt from retrieved chunks
const chromaResponse = $input.first().json;
const query = $('Pass Query + DocId').first().json.query;

const documents = chromaResponse.documents || chromaResponse.data?.documents;
const arr = Array.isArray(documents) ? documents[0] : [];
const context = (arr && arr.length) ? arr.join('\n\n---\n\n') : '(No relevant sections found.)';

const prompt = `You are a document analyst. Use only the following context from the document to answer the question. If the answer is not in the context, say so.

Context:
${context}

Question: ${query}

Answer (concise, plain text):`;

const groqBody = {
  model: 'llama-3.1-8b-instant',
  messages: [{ role: 'user', content: prompt }],
  max_tokens: 2048,
  temperature: 0.3
};

return [{ json: { groqBodyJson: JSON.stringify(groqBody) } }];
